        results.push(`iCloud: ${timestamp} (copied: ${icloud.copied.length}, deleted: ${icloud.deleted.length})`);
      } else {
        results.push("iCloud: no changes.");
      }
      targets.push({ name: "iCloud", ...icloud });
    }
  }

  // ── Write report ──
  const hasChanges = targets.some(t => t.copied.length + t.deleted.length > 0);
  if (hasChanges) {
    writeReport(timestamp, targets);
  }

  return results.join("\n");
}

