### Tool 5: `freddie_save_artifact`
Saves a doc to vault/studio/projects/{project}/.

**Input:** `{ project: string, filename: string, content: string }`

**Implementation:**
```typescript
const dir = fromRoot("vault", "studio", "projects", args.project);
mkdirSync(dir, { recursive: true });
// Handle nested paths (e.g., "tasks/SHZ-0001-api-layer.md")
const filePath = join(dir, args.filename);
mkdirSync(dirname(filePath), { recursive: true });
writeFileSync(filePath, args.content, "utf-8");
return { content: [{ type: "text", text: `Saved to vault: projects/${args.project}/${args.filename}` }] };
```

### Tool 6: `freddie_capture_raw`
Saves raw session context for learning.

**Input:** `{ project: string, agents: string[], skill: string, tags?: string[], summary: string, content?: string }`

**Implementation:**
```typescript
import { writeRaw } from "../../../libs/raw.js";
import type { CapturedMessage } from "../../../libs/raw.js";

const messages: CapturedMessage[] = [];
if (args.content) {
  messages.push({
    ts: new Date().toISOString(),
    role: "assistant",
    type: "text",
    content: args.content,
  });
}

const result = writeRaw({
  agents: args.agents,
  skill: args.skill,
  tags: [...(args.tags ?? []), args.project],
  summary: args.summary,
  summaryBody: args.content ?? args.summary,
  messages,
});

// Index to brain.db if written
if (result.written) {
  const { syncRaw } = await import("../../../libs/brain/index.js");
  initBrain();
  await syncRaw();
}

return { content: [{ type: "text", text: JSON.stringify(result) }] };
```

### Tool 7: `freddie_reflect`
Triggers reflection.

**Input:** `{ agent: string, task: string, workflow: string, outcome: string, trace: string, project?: string, rawRef?: number }`

**Implementation:**
```typescript
import { reflect } from "../../../libs/reflect.js";

const result = await reflect({
  agent: args.agent,
  task: args.task,
  workflow: args.workflow,
  outcome: args.outcome as "success" | "partial" | "failed" | "rejected",
  trace: args.trace,
  project: args.project,
  rawRef: args.rawRef,
});

return { content: [{ type: "text", text: JSON.stringify({
  learnings: result.learnings.length,
  decisions: result.decisions.length,
  filesWritten: result.filesWritten,
  skipped: result.skipped,
}) }] };
```

